12	export function nextGeneration(cells: Cell[]): Cell[] {
13	  const liveSet = new Set<string>();
14	  for (const [x, y] of cells) {
15	    liveSet.add(key(x, y));
16	  }
17	
18	  const neighborCounts = new Map<string, number>();
19	
20	  for (const [x, y] of cells) {
21	    for (let dx = -1; dx <= 1; dx++) {
22	      for (let dy = -1; dy <= 1; dy++) {
23	        if (dx === 0 && dy === 0) continue;
24	        const nx = x + dx;
25	        const ny = y + dy;
26	        const k = key(nx, ny);
27	        neighborCounts.set(k, (neighborCounts.get(k) ?? 0) + 1);
28	      }
29	    }
30	  }
31	
32	  const result: Cell[] = [];
33	  for (const [k, count] of neighborCounts) {
34	    const isAlive = liveSet.has(k);
35	    if (isAlive && (count === 2 || count === 3)) {
36	      result.push(parseKey(k));
37	    } else if (!isAlive && count === 3) {
38	      result.push(parseKey(k));
39	    }
40	  }
41	
42	  return result;
43	}
